INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp67i06g05jrlk9cox319f0f', 'cmp66xism00gulktgymbgw5v8', 'Титович Александр Юрьевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '3', 'Нормальный учебный трек: прошёл все модули, документ получил. Ни эйфории, ни разочарования — ровный рабочий материал для старта в теме безопасности.', 't', '2026-04-15 23:22:19.299'),
('cmp67i06h05jvlk9cc674j7pq', 'cmp66xisq00h0lktg91196zjc', 'Яковлева Евгения Николаевна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-23, 3 курс', '4', 'На третьем курсе как раз пригодился такой системный курс. Завершил полностью, сертификат приложу к портфолио. За минус — хотелось бы чуть больше видео, но текст хороший.', 't', '2026-04-10 23:08:51.283'),
('cmp67i06i05jxlk9cmyb4uw68', 'cmp66xiyq00h3lktgy03kdgcn', 'Андросов Эдуард Михайлович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '4', 'На старших курсах заочки материал заходит лучше, когда всё по шагам. Прошёл полностью. Документ получил — четвёрка с уверенностью.', 't', '2026-04-09 21:58:17.296'),
('cmp67i05705f1lk9c2l3qza5i', 'cmp65v9ci00aflksapmw0641n', 'Жарникова Кира', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-17 11:05:03.864'),
('cmp67i05b05fflk9cw5qeajjt', 'cmp65v9co00axlksac6kupbrn', 'Слепцова Александрина', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-13 22:20:36.09'),
('cmp67i05c05fhlk9ct7xhqxtr', 'cmp65v9cq00b0lksa8rgmi8eu', 'Усольцев Родион', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-13 04:20:04.029'),
('cmp67i05c05fjlk9c2vavidin', 'cmp65v9cr00b3lksa44s0sp84', 'Федотов Иван', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/2, 2 курс', '4', 'На старших курсах заочки материал заходит лучше, когда всё по шагам. Прошёл полностью. Документ получил — четвёрка с уверенностью.', 't', '2026-04-15 05:38:09.712'),
('cmp67i06l05k3lk9cbtl8f5qe', 'cmp66xiyz00hclktgz4bcj65u', 'Винокуров Илья Дьулустанович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '5', 'Заочно учиться непросто, но здесь всё разложено по полочкам: понятно, что делать каждый день. Курс завершил, сертификат забрал — горжусь.', 't', '2026-04-12 08:28:42.141'),
('cmp67i06l05k5lk9c2nfh68j3', 'cmp66xiz000hflktgtrz1q0ys', 'Гаврильева Анастасия Сергеевна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-11 09:14:37.918'),
('cmp67i06m05k7lk9csscycib8', 'cmp5md605001ognc02kmbz66z', 'Слепцов Виктор Александрович', 'Якутский гуманитарный колледж, группа КИ-24, 3 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-04-11 16:06:45.874'),
('cmp67i06m05k9lk9cibkbcfzm', 'cmp66xiz200hilktglibrqlpo', 'Гафуров Артур Абдурахманович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '4', 'На старших курсах заочки материал заходит лучше, когда всё по шагам. Прошёл полностью. Документ получил — четвёрка с уверенностью.', 't', '2026-04-15 09:04:20.3'),
('cmp67i06m05kblk9c6z7lmqy6', 'cmp66xiz300hllktgi4masnwq', 'Григорьев Роберт Христофорович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '2', 'Курс закончил, но мотивация была только «чтобы сдать». Местами слишком много текста подряд, практика спасает. Итог — удовлетворительно.', 't', '2026-04-11 21:56:07.669'),
('cmp67i06n05kdlk9cy3ft1v0q', 'cmp66xiz500holktgwdqfuw6x', 'Гуляева Айлана Алтановна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-12 16:16:00.162'),
('cmp67i06r05krlk9cf5fjwp28', 'cmp66xizg00i9lktgbzqp89zs', 'Потапов Еремей Михайлович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '3', 'Прошла курс целиком. Нормально для программы: тесты честные, по практике комментарии полезные. Без «вау», но знания по ИБ реально прибавились.', 't', '2026-04-12 12:21:14.804'),
('cmp67i06o05khlk9cups5oiai', 'cmp66xiz800hulktgrni67yzv', 'Егоров Эрсан Сергеевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '5', 'Отлично структурировано: от простого к сложному, везде понятно, зачем этот шаг. Практика с ручной проверкой мотивировала не халтурить. После выдачи сертификата спокойно рассказываю одногруппникам, с чего начать ИБ.', 't', '2026-04-13 17:59:50.582'),
('cmp67i06p05kjlk9cgqwoti2h', 'cmp66xiza00hxlktgfnmoxrvx', 'Иванова Алина Владимировна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '3', 'Ровный курс, прошёл до конца. Тесты справедливые, практика полезная. Четвёрку не ставлю из‑за ощущения «чуть не дожали» финал.', 't', '2026-04-14 02:26:17.945'),
('cmp67i06p05kllk9c62hoezx8', 'cmp66xizb00i0lktght0om4n8', 'Кучер Михаил Михайлович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '3', 'Ровный курс, прошёл до конца. Тесты справедливые, практика полезная. Четвёрку не ставлю из‑за ощущения «чуть не дожали» финал.', 't', '2026-04-11 03:02:11.747'),
('cmp67i06q05knlk9ce09c80or', 'cmp66xizc00i3lktgnmybcogk', 'Оконешников Максим Николаевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '5', 'Отлично: и фишинг, и устройства, и сети — без перегруза. Закрыл всё, сертификат приятный бонус. Одногруппникам уже скинул ссылку.', 't', '2026-04-10 21:50:52.969'),
('cmp67i06q05kplk9cpetk55ws', 'cmp66xize00i6lktgfzon6mgd', 'Омукова Туйара Викторовна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '3', 'Ровный курс, прошёл до конца. Тесты справедливые, практика полезная. Четвёрку не ставлю из‑за ощущения «чуть не дожали» финал.', 't', '2026-04-15 22:01:30.269'),
('cmp67i05d05fllk9ckjxh80id', 'cmp66xhsv00b6lktggsy9k7l3', 'Блешбаев Даурен', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-22, 5 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-12 12:58:19.641'),
('cmp67i06s05kxlk9ci64xnseg', 'cmp66xizj00iflktg748mt29e', 'Ребров Эрхан Владимирович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '2', 'Сертификат получил, но вовлечённость просела к середине: много текста, мало «быстрых побед». Для обязательной программы сойдёт, сам бы не выбрал.', 't', '2026-04-11 11:16:02.031'),
('cmp67i06t05kzlk9cw1frkz8q', 'cmp66xizk00iilktg907rlm84', 'Ремпель Ангелина Николаевна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '2', 'Курс закончил, но мотивация была только «чтобы сдать». Местами слишком много текста подряд, практика спасает. Итог — удовлетворительно.', 't', '2026-04-10 16:56:07.086'),
('cmp67i06t05l1lk9c1ys573qu', 'cmp66xizl00illktgsbgqb6dz', 'Сафаров Руслан Махмудович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '4', 'Прошёл курс до конца, материал связный. Практика с обратной связью — сильная сторона. Не идеально, но уверенная четвёрка.', 't', '2026-04-12 18:18:06.708'),
('cmp67i06u05l3lk9c61ddq472', 'cmp66xizn00iolktgmrtzgpgc', 'Стальнов Евгений Викторович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '5', 'Сильная линейка модулей, всё связано с реальными ошибками пользователей. Прошёл до конца без «затыков». Сертификат — приятное подтверждение, что не зря вложился.', 't', '2026-04-13 20:56:18.18'),
('cmp67i06v05l7lk9cbiad5ks1', 'cmp66xizq00iulktgdolpvn5w', 'Третьякова Дарья Николаевна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '3', 'Прошла полностью, сертификат получила. В целом нормально: базу по ИБ собрала, тесты адекватные. Без восторга — иногда хотелось короче формулировок и больше живых примеров из учебной сети колледжа.', 't', '2026-04-13 22:26:13.482');